import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { clearAuth } from '../api';
import {
  Menu, X, Home, MessageSquare,
  AlertTriangle, Bell, Users, LogOut
} from 'lucide-react';

const navItems = [
  { name: 'Home', path: '/user/home', icon: Home },
  { name: 'Feedback', path: '/user/feedback', icon: MessageSquare },
  { name: 'Complaint', path: '/user/complaint', icon: AlertTriangle },
  { name: 'Notices', path: '/user/notices', icon: Bell },
  { name: 'Societies', path: '/user/societies', icon: Users },
];

const Navbar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

  return (
    <motion.nav
      initial={{ y: -60, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.4 }}
      className="sticky top-0 z-[1000] w-full border-b border-white/10 
      bg-[#080e1a]/80 backdrop-blur-xl shadow-lg"
    >
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="flex h-16 items-center justify-between">

          {/* Logo */}
          <motion.div
            whileHover={{ scale: 1.05 }}
            onClick={() => navigate('/user/home')}
            className="flex cursor-pointer items-center gap-2 group"
          >
            <motion.div
              whileHover={{ rotate: 15 }}
              className="flex h-10 w-10 items-center justify-center rounded-xl 
              bg-amber-500/10 text-amber-500 shadow-inner"
            >
              <span className="text-2xl font-bold">⬡</span>
            </motion.div>

            <span className="text-xl font-bold tracking-tight text-amber-500">
              HostelMate
            </span>
          </motion.div>

          {/* Desktop Links */}
          <div className="hidden md:flex md:items-center md:gap-2 relative">

            {navItems.map(({ name, path, icon: Icon }) => {
              const isActive = location.pathname === path;

              return (
                <motion.div
                  key={path}
                  whileHover={{ y: -2 }}
                  className="relative"
                >
                  <Link
                    to={path}
                    className={`relative flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all
                    ${isActive
                        ? 'text-amber-400'
                        : 'text-slate-400 hover:text-white'
                      }`}
                  >
                    <Icon size={16} />
                    {name}

                    {/* Animated Underline */}
                    <motion.span
                      layoutId="nav-indicator"
                      className={`absolute left-1/2 bottom-0 h-[2px] bg-amber-400 transition-all
                      ${isActive ? 'w-3/4 -translate-x-1/2' : 'w-0'}`}
                    />
                  </Link>

                  {/* Glow effect */}
                  {isActive && (
                    <motion.div
                      layoutId="nav-glow"
                      className="absolute inset-0 rounded-lg bg-amber-500/10 blur-md -z-10"
                    />
                  )}
                </motion.div>
              );
            })}

            {/* Logout */}
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={handleLogout}
              className="ml-4 flex items-center gap-2 rounded-lg px-4 py-2 text-sm font-medium
              text-red-400 border border-red-500/20 bg-red-500/10
              hover:bg-red-500/20 shadow-sm hover:shadow-md transition-all"
            >
              <LogOut size={16} />
              Logout
            </motion.button>
          </div>

          {/* Mobile Button */}
          <div className="md:hidden">
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={() => setMenuOpen(!menuOpen)}
              className="rounded-lg p-2 text-amber-500 hover:bg-amber-500/10"
            >
              {menuOpen ? <X size={28} /> : <Menu size={28} />}
            </motion.button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {menuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.3 }}
            className="md:hidden border-t border-white/5 bg-[#0b1221]"
          >
            <div className="space-y-2 px-4 pb-6 pt-4">

              {navItems.map(({ name, path, icon: Icon }, i) => {
                const isActive = location.pathname === path;

                return (
                  <motion.div
                    key={path}
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.05 }}
                  >
                    <Link
                      to={path}
                      onClick={() => setMenuOpen(false)}
                      className={`flex items-center gap-3 rounded-xl px-4 py-3 text-base font-medium
                      ${isActive
                          ? 'bg-amber-500/10 text-amber-400 ring-1 ring-amber-500/20'
                          : 'text-slate-400 hover:bg-white/5'
                        }`}
                    >
                      <Icon size={20} />
                      {name}
                    </Link>
                  </motion.div>
                );
              })}

              <motion.button
                whileTap={{ scale: 0.95 }}
                onClick={() => { handleLogout(); setMenuOpen(false); }}
                className="mt-4 flex w-full items-center gap-3 rounded-xl px-4 py-3 text-base font-medium
                text-red-400 border border-red-500/20 bg-red-500/10"
              >
                <LogOut size={20} />
                Logout
              </motion.button>

            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
};

export default Navbar;
